VALUES
  ('aboriginal-a5729396-moex-00454', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-110-01c5eaab', 'sub-aboriginal-a5729396-05', NULL, 'single_choice', '「梁紅玉是南宋名將韓世忠之妻，曾助夫擊鼓作戰，打退金兵；如此女子，堪稱□□□□。」下列選 項的成語，何者適合填入空格中？', '["一顧傾城", "舉案齊眉", "鬚髯如戟", "巾幗鬚眉"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:48+00:00", "source_pdf_sha1": "e5bf3f0d4288", "answer_pdf_sha1": "38e0530a220d", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "605", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
  ('aboriginal-a5729396-moex-00455', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-110-01c5eaab', 'sub-aboriginal-a5729396-05', NULL, 'single_choice', '下列「」中成語應用，何者完全正確？', '["小明考試作弊，居然沒有被發現，真是「天助自助」啊", "老張是「一諾千金」的人，事情交給他，你就可以放心了", "他「目不見睫」看著我，眼神傳送強烈電波，我想他是愛上我了", "他一心一意要到巴黎學畫，效法「邯鄲學步」，在藝術之都接受西方文化洗禮"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:48+00:00", "source_pdf_sha1": "e5bf3f0d4288", "answer_pdf_sha1": "38e0530a220d", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "605", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
  ('aboriginal-a5729396-moex-00456', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-110-01c5eaab', 'sub-aboriginal-a5729396-05', NULL, 'single_choice', '下列「」中的成語，使用正確的是：', '["老陳庭訓甚嚴，訓練孩子要「名韁利鎖」，留意於名實相符", "李老師任教數十年，始終「師心自用」，一本初衷的關懷學生", "詐騙集團嫌疑人果然「凶終隙末」，最終還是露出破綻，被移送法辦", "老張生性淡泊名利，常抱「富貴浮雲」的態度，因此政治生涯始終清廉自持"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:48+00:00", "source_pdf_sha1": "e5bf3f0d4288", "answer_pdf_sha1": "38e0530a220d", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "605", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
  ('aboriginal-a5729396-moex-00457', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-110-01c5eaab', 'sub-aboriginal-a5729396-05', NULL, 'single_choice', '下列文句，何者沒有語病？', '["黑色在五行中屬火，廚房屬水，在風水上相剋，因此在裝潢時不介意使用黑色", "立法院尚未完成消毒，呼籲相關部會的訪客，一定要務必注意，落實防疫工作", "人氣美食名店名不虛傳，真可謂「吃一口，欲罷不能；來一次，終生成主顧」", "我們致力提供優質服務，以配合您的需求：會籍級別愈高，所享的服務就愈超越"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:48+00:00", "source_pdf_sha1": "e5bf3f0d4288", "answer_pdf_sha1": "38e0530a220d", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "605", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
  ('aboriginal-a5729396-moex-00458', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-110-01c5eaab', 'sub-aboriginal-a5729396-05', NULL, 'single_choice', '下列題辭之使用，何者不恰當？', '["壽慶：道範長存", "喬遷：里仁為美", "婚嫁：桃夭及時", "入營：移孝作忠"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:48+00:00", "source_pdf_sha1": "e5bf3f0d4288", "answer_pdf_sha1": "38e0530a220d", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "605", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
  ('aboriginal-a5729396-moex-00459', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-110-01c5eaab', 'sub-aboriginal-a5729396-05', NULL, 'single_choice', '下列匾額，使用正確的選項是：', '["中醫診所：杏壇春暖", "農場種植：功在桑梓", "立法委員：克孚眾望", "報館開業：陶朱媲美"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:48+00:00", "source_pdf_sha1": "e5bf3f0d4288", "answer_pdf_sha1": "38e0530a220d", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "605", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
  ('aboriginal-a5729396-moex-00460', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-110-01c5eaab', 'sub-aboriginal-a5729396-05', NULL, 'single_choice', '下列選項中，何者適用於對他人稱呼自己的幼輩如「弟」、「姪」之前？', '["家", "舍", "敝", "愚"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:48+00:00", "source_pdf_sha1": "e5bf3f0d4288", "answer_pdf_sha1": "38e0530a220d", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "605", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
  ('aboriginal-a5729396-moex-00461', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-110-01c5eaab', 'sub-aboriginal-a5729396-05', NULL, 'single_choice', '關於書信的啟封詞，下列敘述何者正確？', '["對平輩可用「安啟」", "對長輩可用「台啟」", "對師長可用「道啟」", "寫明信片可用「啟」"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:48+00:00", "source_pdf_sha1": "e5bf3f0d4288", "answer_pdf_sha1": "38e0530a220d", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "605", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
  ('aboriginal-a5729396-moex-00462', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-110-01c5eaab', 'sub-aboriginal-a5729396-05', NULL, 'single_choice', '下列「」中的語詞，何者不是傳說中的神馬或良駒？', '["「飛黃」騰達", "「騏驥」一躍，不能十步", "「赤兔」思念舊主，絕食而死", "「金烏」玉兔最無情，驅馳不暫停"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:48+00:00", "source_pdf_sha1": "e5bf3f0d4288", "answer_pdf_sha1": "38e0530a220d", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "605", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
  ('aboriginal-a5729396-moex-00463', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-110-01c5eaab', 'sub-aboriginal-a5729396-05', NULL, 'single_choice', '「八荒霍霍驚仰首，空中□□逐日走。拔山倒海事事終，不追白日非英雄！果然手捉黃金烏，問公此 樂胡為乎？如何口渴顏色槁，一枝杖作鄧林草？」□□中所詠神話英雄為：', '["夸父", "刑天", "精衛", "盤古"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:48+00:00", "source_pdf_sha1": "e5bf3f0d4288", "answer_pdf_sha1": "38e0530a220d", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "605", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL)
